//帮别人调
#include<bits/stdc++.h>
using namespace std;
#define ll long long int 
#define endl '\n'
#define pii pair<ll,ll>
#define diff 1e-7
ll _;
ll n;
double l, r;
double a[20];//这里是实数
double f(double x) 
{
    double ans = 0, k = 1;
    for (int i = 0; i <= n; i++)//写反了
    {
        ans += k * a[i];
        k *= x;
    }
    return ans;
}

void solve()
{
    cin >> n >> l >> r;
    for (int i = n; i >= 0 ; i--)//从高到低输入
    {
        cin >> a[i];
    }
    while (r - l >= diff)
    {
        double m1 = l + (r - l) / 3.0;
        double m2 = r - (r - l) / 3.0;
        if (f(m1) < f(m2))
        {
            l = m1;
        }
        else r = m2;
    }
    printf("%.5lf", l);//保留5位小数，直接输出l
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0), cout.tie(0);
    _ = 1;
    while (_--)
    {
        solve();
    }
    return 0;
}
